def mergeSort(head: Node) -> Node: if not head: return head
    slow, fast = head, head
    while fast.next and fast.next.next:
        slow = slow.next
        fast = fast.next.next
    mid = slow.next
    slow.next = None
    return merge(head, mergeSort(mid))

def merge(head1: Node, head2: Node) -> Node:
    if not head1:
        return head2
    if not head2:
        return head1
    if head1.val < head2.val:
        head1.next = merge(head1.next, head2)
        return head1
    else:
        head2.next = merge(head1, head2.next)
        return head2

class Node:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def mergeSort(self, head: Node) -> Node:
        return mergeSort(head)

