bool solve(node* &head) { if (!head) return true; if (!head->next) return true; node* prev; node* curr = head; while (curr) { prev = curr; curr = curr->next; if (curr) { prev->next = curr->next; } if (!mergeSort(prev, curr)) return false; } return true; }

void Solution::mergeSort(node* &head, node* &tail) {
    if (!head) return;
    node* mid = findMiddle(head);
    node* nextToMid = mid->next;
    mid->next = NULL;

    if (solve(head)) return;
    if (solve(nextToMid)) return;
    mergeLists(&head, &nextToMid);
}

node* findMiddle(node* head) { node* slow = head; node* fast = head; while (fast->next && fast->next->next) { slow = slow->next; fast = fast->next->next; } return slow; }

void mergeLists(node** head1, node** head2) {
    if (!(*head1)) { *head1 = *head2; return; }
    if (!(*head2)) return;
    if ((*head1)->val < (*head2)->val) { node* next = (*head1)->next; (*head1)->next = mergeLists(&((*head1)->next), head2); return; }
    if ((*head2)->val < (*head1)->val) { node* next = (*head2)->next; (*head2)->next = mergeLists(head1, &((*head2)->next)); return; }
    node* next1 = (*head1)->next; node* next2 = (*head2)->next; node* merge = new node((*head1)->val); merge->next = mergeLists(&next1, &next2); *head1 = merge; }

